import emailjs from 'emailjs-com';
import React from 'react';
import { Button, Form, Toast } from 'react-bootstrap';
import { useTranslation } from 'react-i18next';
import Lottie from 'react-lottie';
import { Element } from 'react-scroll';
import * as animationData from '../../assets/inbox-notification.json';
import './Contact.scss';

const defaultOptions = {
	loop: true,
	autoplay: true,
	animationData: animationData.default,
	rendererSettings: {
		preserveAspectRatio: 'xMidYMid slice',
	},
};

export default function Contact({ odd }) {
	const { t } = useTranslation();
	const [show, setShow] = React.useState(false);
	const [form, setForm] = React.useState({});

	React.useEffect(() => {
		emailjs.init('user_drrq9KisF3qw6AXmrVjHH');
	}, []);

	function sendEmail(e) {
		e.preventDefault();

		const fromName = form.name;
		const emailFrom = form.email;
		const messageHTML = form.subject;

		const templateParams = {
			reply_to: 'caba9313@gmail.com',
			from_name: fromName,
			email_from: emailFrom,
			message_html: messageHTML,
		};

		const serviceID = 'default_service';
		const templateID = 'template_1SUmaJ5Y';

		emailjs.send(serviceID, templateID, templateParams).then(() => {
			setForm({});
			setShow(true);
		});

		return false;
	}

	/**
	 *
	 * @param {KeyboardEvent} e
	 */
	function changeInput(e) {
		setForm({
			...form,
			[e.target.name]: e.target.value,
		});
	}

	const isButtonDisabled = !form.name || !form.email || !form.subject;

	return (
		<Element name="contact">
			<section>
				<div className="Contact mb-5">
					<div className="row">
						<div className={`col-sm-12 col-md-6 ${odd ? ' offset-md-6 text-right ' : ''}`}>
							<h1 className="uppercase"> {t('contact')} </h1>
							<a
								className="undecorate"
								href="https://open.spotify.com/track/0S5otf3yhH2NIozxJPJTeV?si=82k3tl8CSaKTtqsZZdRCNw"
								rel="noopener noreferrer"
								target="_blank"
							>
								<h6> LET&apos;S GET RIDICULOUS </h6>
							</a>
						</div>
					</div>
					<div className="row">
						<div className="col-sm-12 col-md-6 row justify-content-center align-content-center flex-column">
							<p>If you have a great project, I&apos;ll make it better</p>
							<Lottie height="auto" options={defaultOptions} width="50%" />
						</div>
						<div className="col-sm-12 col-md-6">
							<Form onSubmit={sendEmail}>
								<Form.Group controlId="name">
									<Form.Label> {t('name')}</Form.Label>
									<Form.Control
										name="name"
										onChange={changeInput}
										placeholder={t('enter-name')}
										required
										type="text"
									/>
								</Form.Group>

								<Form.Group controlId="email">
									<Form.Label>{t('email')}</Form.Label>
									<Form.Control
										name="email"
										onChange={changeInput}
										placeholder={t('spam')}
										required
										type="email"
									/>
								</Form.Group>

								<Form.Group controlId="message">
									<Form.Label>{t('message')}</Form.Label>
									<Form.Control
										as="textarea"
										name="subject"
										onChange={changeInput}
										placeholder={t('concerns')}
										required
										rows="5"
									/>
								</Form.Group>

								<div className="row justify-content-end">
									<Toast
										animation
										autohide
										delay={7000}
										onClose={() => setShow(false)}
										show={show}
										style={{
											position: 'absolute',
											top: 0,
											right: 0,
											background: '#157af6',
											color: 'white',
										}}
									>
										<Toast.Body> Estarémos trabajando muy pronto ;) </Toast.Body>
									</Toast>
									<Button
										disabled={isButtonDisabled}
										type="submit"
										variant={isButtonDisabled ? 'outline-primary' : 'primary'}
									>
										{t('send')}
									</Button>
								</div>
							</Form>
						</div>
					</div>
				</div>
			</section>
		</Element>
	);
}
